{
    "level": "A1–A2",
    "intro": "У цій темі ти закріпиш <strong>am / is / are</strong>, форми <strong>was / were</strong>, модель <strong>will be</strong>, заперечення, питання та <strong>there is / there are</strong>.",
    "rules": [
        {
            "label": "Present Forms",
            "color": "emerald",
            "text": "Почни з <strong>am / is / are</strong> у простих реченнях.",
            "example": "I am late. / She is ready. / They are here."
        },
        {
            "label": "Past and Future",
            "color": "blue",
            "text": "Далі додай <strong>was / were</strong> і модель <strong>will be</strong>.",
            "example": "I was tired yesterday. / They will be here soon."
        },
        {
            "label": "Questions and There",
            "color": "amber",
            "text": "Окремо потренуй питання без <strong>do / does / did</strong> і моделі з <strong>there</strong>.",
            "example": "Were they ready? / Will she be late? / There is a book on the table."
        }
    ]
}

{
    "title": "1. Стартовий набір",
    "intro": "Цей підрозділ веде від найпростіших форм до минулого, майбутнього й моделей з there.",
    "items": [
        {
            "label": "A1",
            "title": "Present Forms",
            "subtitle": "am / is / are у коротких стверджувальних реченнях."
        },
        {
            "label": "A1",
            "title": "Negatives",
            "subtitle": "am not, is not, are not і поширені скорочення."
        },
        {
            "label": "A1",
            "title": "Questions and Short Answers",
            "subtitle": "Am I...?, Is he...?, Are they...? і короткі відповіді."
        },
        {
            "label": "A1–A2",
            "title": "Past Forms",
            "subtitle": "was / were, заперечення і питання у минулому."
        },
        {
            "label": "A1–A2",
            "title": "Future",
            "subtitle": "will be, won't be і прості майбутні питання."
        },
        {
            "label": "A1–A2",
            "title": "There Is / There Are",
            "subtitle": "Опис того, що є або немає в певному місці."
        }
    ]
}

{
    "title": "2. Що ти відпрацюєш",
    "sections": [
        {
            "label": "am / is / are",
            "color": "emerald",
            "description": "Побачиш, яку форму брати з <strong>I</strong>, <strong>he / she / it</strong> та <strong>you / we / they</strong>.",
            "examples": [
                {
                    "en": "I am tired. / She is a student. / They are at work.",
                    "ua": "Базові моделі для стану, ролі та місця."
                }
            ]
        },
        {
            "label": "was / were / will be",
            "color": "blue",
            "description": "Додаси минулі й майбутні форми <strong>to be</strong>, щоб говорити про те, що було і що буде.",
            "examples": [
                {
                    "en": "He was at home yesterday. / They will be ready soon.",
                    "ua": "Минулі й майбутні форми дієслова to be."
                }
            ]
        },
        {
            "label": "Questions and there",
            "color": "amber",
            "description": "Навчишся будувати питання й короткі відповіді та окремо описувати наявність у місці.",
            "examples": [
                {
                    "en": "Was she tired? / Will they be here? / There are two chairs in the kitchen.",
                    "ua": "Питання, короткі відповіді й модель для опису наявності."
                }
            ]
        }
    ]
}
